 30→public class SpacingAroundColonRule : StandardRule("colon-spacing") {
 31→    override fun beforeVisitChildNodes(
 32→        node: ASTNode,
 33→        autoCorrect: Boolean,
 34→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
 35→    ) {
 36→        if (node is LeafPsiElement && node.textMatches(":") && !node.isPartOfString() && !node.isPartOfComment()) {
 37→            if (node.isPartOf(ANNOTATION) || node.isPartOf(ANNOTATION_ENTRY)) {
 38→                // todo: enforce "no spacing"
 39→                return
 40→            }
 41→            val removeSpacingBefore =
 42→                node.parent !is KtClassOrObject &&
 43→                    node.parent !is KtConstructor<*> && // constructor : this/super
 44→                    node.parent !is KtTypeConstraint && // where T : S
 45→                    node.parent?.parent !is KtTypeParameterList
 46→            val prevLeaf = node.prevLeaf()
 47→            if (prevLeaf != null && prevLeaf.isWhiteSpaceWithNewline()) {
 48→                emit(prevLeaf.startOffset, "Unexpected newline before \":\"", true)
 49→                if (autoCorrect) {
 50→                    val parent = node.parent
 51→                    val prevNonCodeElements = node.siblings(forward = false, withItself = false)
 52→                        .takeWhile { it.node.isWhiteSpace() || it.node.isPartOfComment() }.toList()
 53→                    when {
 54→                        parent is KtProperty || parent is KtNamedFunction -> {
 55→                            val equalsSignElement = node.siblings(forward = true, withItself = false)
 56→                                .firstOrNull { it.node.elementType == EQ }
 57→                            if (equalsSignElement != null) {
 58→                                equalsSignElement.nextSibling?.takeIf { it.node.isWhiteSpace() }?.delete()
 59→                                prevNonCodeElements.forEach { parent.addAfter(it, equalsSignElement) }
 60→                            }
 61→                            val blockElement = node.siblings(forward = true, withItself = false)
 62→                                .firstIsInstanceOrNull<KtBlockExpression>()
 63→                            if (blockElement != null) {
 64→                                prevNonCodeElements
 65→                                    .let { if (it.first().node.isWhiteSpace()) it.drop(1) else it }
 66→                                    .forEach { blockElement.addAfter(it, blockElement.lBrace) }
 67→                            }
 68→                            parent.deleteChildRange(prevNonCodeElements.last(), prevNonCodeElements.first())
 69→                        }
 70→                        prevLeaf.prevLeaf()?.isPartOfComment() == true -> {
 71→                            val nextLeaf = node.nextLeaf()
 72→                            prevNonCodeElements.reversed().forEach {
 73→                                node.treeParent.addChild(it.node, nextLeaf)
 74→                            }
 75→                            if (nextLeaf != null && nextLeaf.isWhiteSpace()) {
 76→                                node.treeParent.removeChild(nextLeaf)
 77→                            }
 78→                        }
 79→                        else -> {
 80→                            val text = prevLeaf.text
 81→                            if (removeSpacingBefore) {
 82→                                prevLeaf.treeParent.removeChild(prevLeaf)
 83→                            } else {
 84→                                (prevLeaf as LeafPsiElement).rawReplaceWithText(" ")
 85→                            }
 86→                            (node as ASTNode).upsertWhitespaceAfterMe(text)
 87→                        }
 88→                    }
 89→                }
 90→            }
 91→            if (node.prevSibling is PsiWhiteSpace && removeSpacingBefore && !prevLeaf.isWhiteSpaceWithNewline()) {
 92→                emit(node.startOffset, "Unexpected spacing before \":\"", true)
 93→                if (autoCorrect) {
 94→                    node.prevSibling.node.treeParent.removeChild(node.prevSibling.node)
 95→                }
 96→            }
 97→            val missingSpacingBefore =
 98→                node.prevSibling !is PsiWhiteSpace &&
 99→                    (
100→                        node.parent is KtClassOrObject || node.parent is KtConstructor<*> ||
101→                            node.parent is KtTypeConstraint || node.parent.parent is KtTypeParameterList
102→                        )
103→            val missingSpacingAfter = node.nextSibling !is PsiWhiteSpace
104→            when {
105→                missingSpacingBefore && missingSpacingAfter -> {
106→                    emit(node.startOffset, "Missing spacing around \":\"", true)
107→                    if (autoCorrect) {
108→                        (node as ASTNode).upsertWhitespaceBeforeMe(" ")
109→                        (node as ASTNode).upsertWhitespaceAfterMe(" ")
110→                    }
111→                }
112→                missingSpacingBefore -> {
113→                    emit(node.startOffset, "Missing spacing before \":\"", true)
114→                    if (autoCorrect) {
115→                        (node as ASTNode).upsertWhitespaceBeforeMe(" ")
116→                    }
117→                }
118→                missingSpacingAfter -> {
119→                    emit(node.startOffset + 1, "Missing spacing after \":\"", true)
120→                    if (autoCorrect) {
121→                        (node as ASTNode).upsertWhitespaceAfterMe(" ")
122→                    }
123→                }
124→            }
125→        }
126→    }
127→}
